import { PostHog } from "posthog-node";

export interface PostHogEnv {
  POSTHOG_PROJECT_TOKEN: string;
  POSTHOG_HOST: string;
}

// Create one client per request. flushAt:1 + flushInterval:0 send events
// immediately because a Worker isolate can terminate before a batch flushes.
export function createPostHog(env: PostHogEnv) {
  return new PostHog(env.POSTHOG_PROJECT_TOKEN, {
    host: env.POSTHOG_HOST,
    flushAt: 1,
    flushInterval: 0
  });
}
